message.content:
{
  "timeline_indicator": {
    "placement": "En la sección del timeline del expediente, junto a cada documento.",
    "visual_treatment": "Utilizar colores distintos: gris para borradores analizados, verde para confirmados. Iconos diferenciadores para cada estado.",
    "copy": "Etiquetas claras: 'Borrador Analizado' y 'Confirmado'.",
    "caveat": "Asegurarse de que los colores sean accesibles y no confundan a los usuarios daltónicos."
  },
  "reanalyze_cta": {
    "label": "Reanalizar",
    "placement": "Cerca del documento en estado de borrador activo, visible al usuario.",
    "behavior": "Al hacer clic, reinicia el ciclo de análisis desde el borrador sin afectar documentos confirmados.",
    "guardrail": "Deshabilitar el botón si no hay un borrador activo para evitar confusiones."
  },
  "analytics_events": [
    {
      "name": "Archivo Seleccionado",
      "when": "Cuando el usuario selecciona un archivo para análisis.",
      "required_fields": ["user_id", "file_id"]
    },
    {
      "name": "Inicio de Análisis",
      "when": "Cuando se inicia el análisis del documento.",
      "required_fields": ["user_id", "file_id"]
    },
    {
      "name": "Borrador Analizado",
      "when": "Cuando un borrador es analizado.",
      "required_fields": ["user_id", "draft_id"]
    },
    {
      "name": "Reanálisis Iniciado",
      "when": "Cuando se hace clic en el botón Reanalizar.",
      "required_fields": ["user_id", "draft_id"]
    },
    {
      "name": "Guardado Confirmado",
      "when": "Cuando un documento es guardado como confirmado.",
      "required_fields": ["user_id", "document_id"]
    }
  ],
  "risks": [
    "Confusión del usuario si los colores no son accesibles.",
    "Posible pérdida de datos si el ciclo de reanálisis no se gestiona correctamente.",
    "Falta de seguimiento de métricas si no se implementan correctamente los eventos de análisis."
  ]
}
